package pe.edu.utp.tmo.service.impl;
import com.google.common.cache.*; import com.google.common.collect.ImmutableList; import com.google.common.base.Preconditions; import java.util.*; import java.util.concurrent.TimeUnit; import org.springframework.stereotype.Service; import pe.edu.utp.tmo.dao.*; import pe.edu.utp.tmo.dto.response.TipificacionResponse; import pe.edu.utp.tmo.model.entity.*; import pe.edu.utp.tmo.model.enums.TipoCaso; import pe.edu.utp.tmo.service.CatalogService;
@Service public class CatalogCacheService implements CatalogService{ private final TipificacionDAO tips; private final SlaDAO slas; private final Cache<String,List<Tipificacion>> cat=CacheBuilder.newBuilder().expireAfterWrite(10,TimeUnit.MINUTES).maximumSize(20).build(); private final Cache<TipoCaso,Optional<ParametroSLA>> sla=CacheBuilder.newBuilder().expireAfterWrite(10,TimeUnit.MINUTES).maximumSize(30).build(); public CatalogCacheService(TipificacionDAO tips,SlaDAO slas){this.tips=tips;this.slas=slas;} public List<TipificacionResponse> listarTipificacionesActivas(){List<Tipificacion> v=cat.getIfPresent("tips"); if(v==null){v=ImmutableList.copyOf(tips.listarActivas()); cat.put("tips",v);} return v.stream().map(t->new TipificacionResponse(t.getId(),t.getNombre())).toList();} public Optional<ParametroSLA> sla(TipoCaso t){Preconditions.checkNotNull(t); Optional<ParametroSLA> v=sla.getIfPresent(t); if(v==null){v=slas.buscarPorTipoCaso(t); sla.put(t,v);} return v;}}
